        gr_manPlan.setColumnReadOnly("staffNm", true);
    } else {
        gr_manPlan.setColumnReadOnly("staffNo", false);
        gr_manPlan.setColumnReadOnly("staffNm", false);
    }
};

scwin.gr_eqPlan_oncellclick = function(rowIndex, columnIndex, columnId) {
